#include <iostream>
#include <string>
#include <iomanip>

class BankAccount {
private:
    double balance;
public:
    BankAccount(double initialBalance = 0.0) {
        if (initialBalance >= 0.0) {
            this->balance = initialBalance;
        } else {
            this->balance = 0.0;
            std::cout << "Warning: Initial balance cannot be negative. Setting to 0.0." << std::endl;
        }
    }
    void deposit(double amount) {
        if (amount > 0.0) {
            this->balance = this->balance + amount;
            std::cout << "Deposit successful. Current balance is now: " << this->balance << std::endl;
        } else if (amount == 0.0) {
            std::cout << "Deposit amount cannot be zero. No action taken." << std::endl;
        } else {
            std::cout << "Deposit amount must be positive. No action taken." << std::endl;
        }
    }
    void withdraw(double amount) {
        if (amount > 0.0) {
            if (this->balance >= amount) {
                this->balance = this->balance - amount;
                std::cout << "Withdrawal successful. Current balance is now: " << this->balance << std::endl;
            } else {
                std::cout << "Insufficient balance for withdrawal. Balance: " << this->balance << ". Attempted: " << amount << ". No action taken." << std::endl;
            }
        } else if (amount == 0.0) {
            std::cout << "Withdrawal amount cannot be zero. No action taken." << std::endl;
        } else {
            std::cout << "Withdrawal amount must be positive. No action taken." << std::endl;
        }
    }
    double getBalance() const {
        double currentBalanceValue = this->balance;
        return currentBalanceValue;
    }
};

int main() {
    std::cout << std::fixed << std::setprecision(2);
    BankAccount account(100.0);
    std::cout << "Initial balance: " << account.getBalance() << std::endl;
    std::cout << "--- Deposit 50.0 ---" << std::endl;
    account.deposit(50.0);
    std::cout << "--- Withdraw 20.0 ---" << std::endl;
    account.withdraw(20.0);
    std::cout << "--- Deposit -10.0 ---" << std::endl;
    account.deposit(-10.0);
    std::cout << "--- Withdraw 200.0 ---" << std::endl;
    account.withdraw(200.0);
    std::cout << "--- Deposit 0.0 ---" << std::endl;
    account.deposit(0.0);
    std::cout << "--- Withdraw 0.0 ---" << std::endl;
    account.withdraw(0.0);
    std::cout << "Final balance: " << account.getBalance() << std::endl;
    return 0;
}
